function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
    }

    // Dijkstra's algorithm with state tracking
