    // hasSwitchUsed is a boolean (0 or 1) indicating whether the switch at this node has been used
    // We use a priority queue to process states in order of increasing cost
    const pq: [number, number, number][] = [[0, 0, 0]]; // [node, hasSwitchUsed, cost]
    const dist: number[][] = Array.from({ length: n }, () => Array(2).fill Infinity);
