        const [u, hasSwitchUsed, cost] = pq.shift()!;
        if (u === n - 1) return cost;
        if (cost > dist[u][hasSwitchUsed]) continue;

        // Traverse all edges from u
        for (const [v, w] of adj[u]) {
            // Normal edge traversal
            if (dist[v][hasSwitchUsed] > cost + w) {
                dist[v][hasSwitchUsed] = cost + w;
                pq.push([v, hasSwitchUsed, dist[v][hasSwitchUsed]]);
