import java.util.PriorityQueue;

public static long solve(long n, long[][] edges) {
    int size = (int) n;
    // Build adjacency list
    int[][] adj = new int[size][];
    for (long[] edge : edges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        int w = (int) edge[2];
        if (adj[u] == null) {
            adj[u] = new int[0];
