        int[] newAdj = new int[adj[u].length + 1];
        System.arraycopy(adj[u], 0, newAdj, 0, adj[u].length);
        newAdj[adj[u].length] = v;
        adj[u] = newAdj;
    }

    // Dijkstra's algorithm with state tracking
    // State: (node, hasSwitchUsed)
    // hasSwitchUsed is 0 or 1 indicating whether the switch at this node has been used
    PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[2] - b[2]);
    pq.offer(new int[]{0, 0, 0}); // [node, hasSwitchUsed, cost]
    long[][] dist = new long[size][2];
