                    dist[v][hasSwitchUsed] = cost + w;
                    pq.offer(new int[]{v, hasSwitchUsed, dist[v][hasSwitchUsed]});
                }

                // Reverse edge traversal if switch hasn't been used
                if (!hasSwitchUsed) {
                    if (dist[v][1] > cost + 2 * w) {
                        dist[v][1] = cost + 2 * w;
                        pq.offer(new int[]{v, 1, dist[v][1]});
                    }
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

